  ('immigration-1aab856d-moex-00160', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '我國首部「國家人權行動計畫」優先推動的八大議題當中，不包含下列何者？', '["居住正義", "商業與人權", "平等與不歧視", "難民權利保障"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00161', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '我國「漁業與人權行動計畫」中，針對漁船船員權益及管理各項工作提出7大因應策略，並在各 策略採取具體行動項目，強化制度與落實執行。請問下列何者非各項執行策略之具體行動？', '["建立及落實直接足額給付船員薪", "提高境內僱用外籍船員勞保投保", "強化跨機關打擊海上人口販運機制", "要求「我國人投資經營外籍漁船（FOC）」適用勞動基準法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00162', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '下列有關境內僱用與境外僱用外籍船員權益比較，何者錯誤？', '["最低聘僱年齡，境內僱用外籍漁工16歲以上，境外僱用外籍漁工為18歲以上", "每月最低工資，境內僱用外籍漁工為新臺幣27,470元，境外僱用外籍漁工為美金650元", "保險，境內僱用外籍漁工為勞保、職業災害保險、健保，境外僱用外籍漁工為商業保險", "每日休息時間，境內僱用外籍漁工24小時內累積休息時間不得低於10小時，境外僱用外籍漁 工不應低於10小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00163', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '根據2022年聯合國提出的「人口販運全球報告」，下列何項剝削類型的被害人占發現案件的最多數？', '["強迫婚姻", "強迫犯罪行為", "性剝削人口販運", "強迫勞動人口販運"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00164', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '根據聯合國發布的「2022年人口販運全球報告」的主要發現，下列何者為正確？', '["氣候變遷加劇人口販運的風險", "執法人員比過去救援出更多的被害人", "由於勞動剝削增加，使得男性被害人數也快速增加", "男性在加害人手中遭受到更嚴重的暴力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00165', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '為強化人口販運之預防、保護與起訴，我國於2023年修正「人口販運防制法」，下列何者並非 本次修正之成果？', '["「實行依我國法律有刑罰規定之行為」列為不法作為之一", "被害人每次申請之居留許可延長為1年效期", "法院審理中，知悉有人口販運嫌疑者，應即移請檢察官鑑別", "加重法定刑期，如摘除器官致人於死，最高可處無期徒刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00166', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '下列有關「移工留才久用方案—開放在臺從事中階技術工作」之敘述，何者錯誤？', '["須為在臺工作滿6年以上的移工", "產業類移工每月經常性薪資須逾新臺幣33,000元或年總薪資逾新臺幣50萬元", "產業類包含製造業、營造業、農業、海洋漁撈", "產業類個別雇主申請中階人力名額，不超過移工核配比率50%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00167', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '外籍配偶在臺居留期間若與臺灣籍配偶離婚，下列敘述何者正確？', '["無論是否有子女，皆因居留原因消失無法繼續居留我國", "家庭暴力被害人若經法院判決離婚，則可繼續居留", "離婚後對在臺灣地區已設有戶籍未成年子女，有撫育事實則可繼續居留", "當其子女成年後，照顧未成年子女理由消失，無法以此原因繼續居留"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00168', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '有關大陸地區人民為臺灣地區人民配偶，其繼承在臺灣地區之遺產或受遺贈者，下列規定何者正確？', '["所得遺產總額不得超過新臺幣200萬元", "經許可依親居留者，得繼承以不動產為標的之遺產", "經許可長期居留者，其遺產之繼承應依照民法遺產之繼承規定", "不動產為臺灣地區繼承人賴以居住者，不得繼承之，於定大陸地區繼承人應得部分時，其價額 不計入遺產總額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00169', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '下列有關依就業服務法持合法工作簽證入臺且經雇主通知失聯之外籍勞工，其在臺生育之未滿18 歲無依子女之適用法令與服務措施，何者錯誤？', '["倘生父不詳，生母為行方不明外國人，則境外協尋生母3個月、境內協尋生母6個月", "協尋期間得暫依生母國籍核發外僑居留證", "若找不到生母且原屬國不認該兒少具有該國國籍者，將依國籍法第2條規定，屬中華民國國籍", "該兒少不受出生日期限制，於取得居留證明文件後即可立即參加健保，不受6個月等待期限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
